SELECT occupancy
FROM occupancy_records
WHERE occupancy_date = '2018-01-01T00:00:00';

SELECT COUNT(*) AS total_records
FROM occupancy_records
WHERE shelter_id = 0;

SELECT name
FROM shelters
ORDER BY name;

SELECT MAX(occupancy) AS max_occupancy
FROM occupancy_records
WHERE facility_id = 1;

SELECT name
FROM shelters
ORDER BY name;

SELECT AVG(occupancy) AS average_occupancy
FROM program_usage
WHERE program_id = 0;

SELECT name, phone
FROM shelters
ORDER BY name ASC;

SELECT occupancy_date
FROM occupancy_records
WHERE _id = 1;

SELECT occupancy
  FROM program_usage
  WHERE program_id = 0 AND occupancy_date = '2018-01-01T00:00:00';

SELECT name
FROM facilities
ORDER BY name ASC;
